import {
  HTMLAttributes,
  useCallback,
  useEffect,
  useState,
} from 'preact/compat';
import { Container } from '@adobe-commerce/elsie/lib';
import { PaymentOnAccount as PaymentOnAccountComponent } from '@/checkout/components/PaymentOnAccount';
import { Money, CompanyCredit } from '@/checkout/data/models';
import { getCompanyCredit } from '@/checkout/api';
import { events } from '@adobe-commerce/event-bus';
import { state } from '@/checkout/lib';
import { CartModel, NegotiableQuoteModel } from '@/checkout/types/storefront';

export interface PaymentOnAccountProps extends HTMLAttributes<HTMLDivElement> {
  initialReferenceNumber?: string;
  onReferenceNumberChange?: (referenceNumber: string) => void;
  onReferenceNumberBlur?: (referenceNumber: string) => void;
}

export const PaymentOnAccount: Container<PaymentOnAccountProps> = ({
  initialReferenceNumber = '',
  onReferenceNumberChange,
  onReferenceNumberBlur,
  ...props
}) => {
  const [isInitialized, setIsInitialized] = useState(false);
  const [companyCredit, setCompanyCredit] = useState<CompanyCredit | null>(
    null
  );
  const [totalAmount, setTotalAmount] = useState<Money | null>(null);
  const [referenceNumber, setReferenceNumber] = useState<string>(
    initialReferenceNumber
  );

  const isAuthenticated = state.authenticated;
  const hasCartRef = Boolean(state.cartId);
  const hasQuoteRef = Boolean(state.quoteId);

  const handleCartData = useCallback((data: CartModel | null) => {
    setTotalAmount(data?.total?.includingTax || null);
  }, []);

  const handleQuoteData = useCallback(
    (data: { quote: NegotiableQuoteModel }) => {
      setTotalAmount(data?.quote?.prices?.grandTotal || null);
    },
    []
  );

  const handleReferenceNumberChange = useCallback(
    (event: Event) => {
      const target = event.target as HTMLInputElement;
      const value = target.value;
      setReferenceNumber(value);
      onReferenceNumberChange?.(value);
    },
    [onReferenceNumberChange]
  );

  const handleReferenceNumberBlur = useCallback(
    (event: Event) => {
      const target = event.target as HTMLInputElement;
      const value = target.value;
      onReferenceNumberBlur?.(value);
    },
    [onReferenceNumberBlur]
  );

  useEffect(() => {
    if (!hasCartRef) return;

    // @ts-ignore
    const onCartData = events.on('cart/data', handleCartData, { eager: true });

    return () => {
      onCartData?.off();
    };
  }, [hasCartRef, handleCartData]);

  useEffect(() => {
    if (!hasQuoteRef) return;

    const onQuoteData = events.on(
      'quote-management/quote-data',
      handleQuoteData,
      { eager: true }
    );

    return () => {
      onQuoteData?.off();
    };
  }, [hasQuoteRef, handleQuoteData]);

  useEffect(() => {
    if (!isAuthenticated) return;

    getCompanyCredit()
      .then((credit) => {
        setCompanyCredit(credit);
      })
      .catch((error) => {
        console.error('Failed to fetch company credit:', error);
        setCompanyCredit(null);
      })
      .finally(() => {
        setIsInitialized(true);
      });
  }, [isAuthenticated]);

  return (
    <div {...props}>
      <PaymentOnAccountComponent
        companyCredit={companyCredit}
        initialized={isInitialized}
        referenceNumber={referenceNumber}
        totalAmount={totalAmount}
        onReferenceNumberBlur={handleReferenceNumberBlur}
        onReferenceNumberChange={handleReferenceNumberChange}
      />
    </div>
  );
};
